CREATE TRIGGER trg_retorno_disponible ON retornos_vehiculo AFTER INSERT AS UPDATE v SET estado='Disponible',updated_at=SYSDATETIME() FROM vehiculos v JOIN asignaciones_vehiculares a ON a.vehiculo_id=v.id JOIN inserted i ON i.asignacion_id=a.id; GO
